def find_max(lst: list) -> int:
    max_val = lst[0]
    for x in lst:
        if x > max_val:
            max_val = x
    return max_val

def make_multiplier(factor: int):
    def multiply(x: int) -> int:
        return x * factor
    return multiply

def merge_intervals(intervals: Iterable[Tuple[int, int]]) -> List[Tuple[int, int]]:
    normalized = sorted((min(a, b), max(a, b)) for a, b in intervals)
    if not normalized:
        return []

    merged = [list(normalized[0])]
    for start, end in normalized[1:]:
        last_start, last_end = merged[-1]
        if start <= last_end:
            merged[-1][1] = max(last_end, end)
        else:
            merged.append([start, end])
    return [tuple(pair) for pair in merged]

def top_k_frequent(nums: List[int], k: int) -> List[int]:
    if k <= 0:
        return []
    counts = Counter(nums)
    ranked = sorted(counts.items(), key=lambda item: (-item[1], item[0]))
    return [value for value, _ in ranked[:k]]

def topo_sort(graph: Dict[str, List[str]]) -> List[str]:
    state: Dict[str, int] = {}
    order: List[str] = []

    def dfs(node: str) -> None:
        status = state.get(node, 0)
        if status == 1:
            raise ValueError(f"cycle detected at {node}")
        if status == 2:
            return
        state[node] = 1
        for dep in graph.get(node, []):
            dfs(dep)
        state[node] = 2
        order.append(node)

    for node in sorted(graph):
        if state.get(node, 0) == 0:
            dfs(node)
    return order

def aggregate_spend(rows: Iterable[Dict[str, object]]) -> List[Dict[str, object]]:
    buckets: Dict[str, Dict[str, object]] = {}
    for row in rows:
        user = str(row["user"])
        amount = float(row["amount"])
        category = str(row["category"])
        bucket = buckets.setdefault(user, {"user": user, "total": 0.0, "categories": set()})
        bucket["total"] += amount
        bucket["categories"].add(category)

    result = []
    for user, payload in buckets.items():
        result.append(
            {
                "user": user,
                "total": round(payload["total"], 2),
                "category_count": len(payload["categories"]),
            }
        )
    return sorted(result, key=lambda item: (-item["total"], item["user"]))

def absolute_value(n: int) -> int:
    if n >= 0:
        return n
    return -n

from typing import Callable, Set


class ServiceError(Exception):
    def __init__(self, code: int, message: str):
        super().__init__(message)
        self.code = code


def _is_retryable(error: ServiceError, retryable_codes: Set[int]) -> bool:
    return error.code in retryable_codes


def execute_with_retry(
    operation: Callable[[], str],
    max_attempts: int,
    retryable_codes: Set[int],
) -> str:
    attempts = 0
    last_error = None
    while attempts < max_attempts:
        try:
            return operation()
        except ServiceError as error:
            last_error = error
            if not _is_retryable(error, retryable_codes):
                raise
            attempts += 1
    raise RuntimeError("retry budget exhausted") from last_error

from typing import Dict, List, Set


RoleGraph = Dict[str, Dict[str, List[str]]]


def resolve_permissions(user_roles: List[str], role_graph: RoleGraph) -> List[str]:
    permissions: Set[str] = set()
    visiting: Set[str] = set()
    visited: Set[str] = set()

    def collect(role: str) -> None:
        if role in visited:
            return
        if role in visiting:
            raise ValueError("cycle detected")
        visiting.add(role)
        node = role_graph.get(role, {"inherits": [], "permissions": []})
        for parent in node.get("inherits", []):
            collect(parent)
        for permission in node.get("permissions", []):
            permissions.add(permission)
        visiting.remove(role)
        visited.add(role)

    for role in user_roles:
        collect(role)
    return sorted(permissions)

from typing import Dict, List


def _line_total(item: Dict[str, float]) -> float:
    return float(item["qty"]) * float(item["unit_price"])


def _apply_discounts(amount: float, discounts: List[Dict[str, float]]) -> float:
    running = amount
    for discount in discounts:
        if discount["type"] == "percent":
            running -= running * float(discount["value"])
        elif discount["type"] == "fixed":
            running -= float(discount["value"])
        running = max(running, 0.0)
    return round(running, 2)


def calculate_invoice(
    items: List[Dict[str, float]],
    discounts: List[Dict[str, float]],
    tax_rate: float,
) -> Dict[str, float]:
    subtotal = sum(_line_total(item) for item in items)
    discounted_subtotal = _apply_discounts(subtotal, discounts)
    tax = round(discounted_subtotal * tax_rate, 2)
    total = round(discounted_subtotal + tax, 2)
    return {
        "subtotal": round(subtotal, 2),
        "discounted_subtotal": discounted_subtotal,
        "tax": tax,
        "total": total,
    }

from typing import Dict, Iterable, List


def _attach_users(db, orders: List[Dict[str, object]]) -> List[Dict[str, object]]:
    unique_user_ids = sorted({int(order["user_id"]) for order in orders})
    users_by_id = db.fetch_users(unique_user_ids)
    hydrated: List[Dict[str, object]] = []
    for order in orders:
        merged = dict(order)
        merged["user"] = users_by_id[int(order["user_id"])]
        hydrated.append(merged)
    return hydrated


def hydrate_orders(db, order_ids: Iterable[int]) -> List[Dict[str, object]]:
    orders = db.fetch_orders(list(order_ids))
    return _attach_users(db, orders)


def mark_orders_shipped(db, order_ids: Iterable[int]) -> int:
    ids = list(order_ids)
    if not ids:
        return 0
    return db.bulk_update_order_status(ids, "shipped")
